import { ref, computed, watch, onMounted } from 'vue';
import { useStore } from 'vuex';
import { useRouter } from 'vue-router';
import { showToast } from '@/components/ToastMessage';
import { auth } from '@/api/auth';
import { deleteAccount } from '@/api/user';
import { SMS_SCENE } from '@/store';
export default {
  __name: 'AccountSettings',
  setup(__props, {
    expose: __expose
  }) {
    __expose();
    const store = useStore();
    const router = useRouter();

    // 用户基本信息
    const userBasicInfo = ref(null);
    const loading = ref(false);

    // 获取用户基本信息
    const fetchUserBasicInfo = async () => {
      try {
        loading.value = true;
        const response = await auth.getUserInfo();
        if (response.data?.code === 200) {
          userBasicInfo.value = response.data.data;
        }
      } catch (error) {
        console.error('获取用户信息失败:', error);
        showToast('获取用户信息失败', 'error');
      } finally {
        loading.value = false;
      }
    };

    // 在组件挂载时获取用户信息
    onMounted(() => {
      if (store.state.isAuthenticated) {
        fetchUserBasicInfo();
      }
    });

    // 监听认证状态变化
    watch(() => store.state.isAuthenticated, isAuthenticated => {
      if (isAuthenticated) {
        fetchUserBasicInfo();
      } else {
        userBasicInfo.value = null;
      }
    });

    // 计算属性
    const username = computed(() => userBasicInfo.value?.user?.username || '未设置');
    const uid = computed(() => userBasicInfo.value?.user?.uid || '暂无');
    const phone = computed(() => userBasicInfo.value?.user?.phone || '');

    // 其他方法和状态保持不变...

    const __returned__ = {
      store,
      router,
      userBasicInfo,
      loading,
      fetchUserBasicInfo,
      username,
      uid,
      phone,
      ref,
      computed,
      watch,
      onMounted,
      get useStore() {
        return useStore;
      },
      get useRouter() {
        return useRouter;
      },
      get showToast() {
        return showToast;
      },
      get auth() {
        return auth;
      },
      get deleteAccount() {
        return deleteAccount;
      },
      get SMS_SCENE() {
        return SMS_SCENE;
      }
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
